import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const applications =
      JSON.parse(localStorage.getItem("applications")) || [];

    const offerLetters =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const merged = applications.map((app) => {
      const offer = offerLetters.find(
        (o) => String(o.applicationId) === String(app.id)
      );

      return {
        ...app,
        offerStatus: offer?.status || "NOT SENT",
        applicationId: app.id,
      };
    });

    setApps(merged);
  }, []);

  const viewOffer = (applicationId) => {
    navigate(`/dashboard/recruitment/offer-preview/${applicationId}`);
  };

  const editOffer = (applicationId) => {
    navigate(`/dashboard/recruitment/offer-letter/${applicationId}`);
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Offer Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {apps.map((app, i) => (
            <tr key={app.id}>
              <td>{i + 1}</td>
              <td>{app.employee}</td>
              <td>{app.email}</td>
              <td>{app.jobTitle}</td>

              <td
                style={{
                  fontWeight: "bold",
                  color:
                    app.offerStatus === "ACCEPTED"
                      ? "green"
                      : app.offerStatus === "REJECTED"
                      ? "red"
                      : "#555",
                }}
              >
                {app.offerStatus}
              </td>

              <td style={{ display: "flex", gap: "10px" }}>
                {app.offerStatus !== "NOT SENT" && (
                  <button onClick={() => viewOffer(app.applicationId)}>
                    View
                  </button>
                )}

                {app.offerStatus !== "ACCEPTED" && (
                  <button
                    style={{ background: "#2563eb", color: "white" }}
                    onClick={() => editOffer(app.applicationId)}
                  >
                    Edit / Resend
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
